SELECT vm_id, SUM(cpu_usage_percentage) AS total_cpu_usage
FROM cpu_usage
GROUP BY vm_id;

SELECT AVG(cpu_usage_percentage) AS avg_cpu_usage
FROM cpu_usage
WHERE vm_id = 1;

SELECT vm_id
FROM memory_usage
WHERE memory_usage_percentage = (SELECT MAX(memory_usage_percentage) FROM memory_usage);

SELECT cpu_usage_percentage
FROM cpu_usage
WHERE vm_id = 1 AND timestamp = '2023-10-01T10:05:00';

SELECT COUNT(*) AS info_logs_count
FROM vm_logs
WHERE user_id = 1 AND log_level = 'info';

SELECT vm_name
FROM virtual_machines
WHERE memory_gb = (SELECT MAX(memory_gb) FROM virtual_machines);

SELECT status, COUNT(*) AS maintenance_count, MIN(start_time) AS earliest_start
FROM maintenance_windows
GROUP BY status;

SELECT COUNT(*) 
FROM vm_snapshots 
WHERE status = 'failed';
